"use client"

import * as React from "react"
import {
  PageHeader,
  LoyaltySummaryCard,
  FilterChips,
  ListCard,
  Badge,
  Button,
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Separator,
  EmptyState,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  List,
  ListItem,
  type FilterChip,
} from "@gunjo/ui"
import {
  IconMapPin,
  IconWalk,
  IconClock,
  IconTicket,
  IconCreditCard,
  IconChevronRight,
  IconBuildingStore,
  IconGift,
  IconCoffee,
  IconCamera,
  IconMoodEmpty,
  IconShieldCheck,
  IconBarcode,
} from "@tabler/icons-react"

import {
  CATEGORIES,
  CATEGORY_LABEL,
  COUPONS,
  COUPON_BY_ID,
  FEATURE,
  MEMBER,
  SPOTS,
  type Category,
  type Coupon,
  type Spot,
} from "./data"
import { Barcode, QrCode, StubFrame } from "./Scannable"

const CATEGORY_ICON: Record<Exclude<Category, "all">, React.ReactNode> = {
  gourmet: <IconBuildingStore className="size-4" />,
  souvenir: <IconGift className="size-4" />,
  cafe: <IconCoffee className="size-4" />,
  sightseeing: <IconCamera className="size-4" />,
}

function gateLabel(gate: Spot["gate"]) {
  return gate === "inside" ? "改札内" : "改札外"
}

function yen(n: number) {
  return `¥${n.toLocaleString("ja-JP")}`
}

export default function StationOutingPage() {
  const [category, setCategory] = React.useState<Category>("all")
  const [openSpot, setOpenSpot] = React.useState<Spot | null>(null)
  const [openCoupon, setOpenCoupon] = React.useState<Coupon | null>(null)
  const [memberOpen, setMemberOpen] = React.useState(false)

  // Category chips with live counts.
  const chips: FilterChip[] = React.useMemo(
    () =>
      CATEGORIES.map((c) => ({
        value: c.value,
        label: c.label,
        icon: c.value === "all" ? undefined : CATEGORY_ICON[c.value],
        count:
          c.value === "all"
            ? SPOTS.length
            : SPOTS.filter((s) => s.category === c.value).length,
      })),
    []
  )

  const visibleSpots = React.useMemo(
    () => (category === "all" ? SPOTS : SPOTS.filter((s) => s.category === category)),
    [category]
  )

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-[420px] flex-col bg-background pb-10">
      <PageHeader
        title="駅ナカ・おでかけ"
        subtitle="東京駅"
        align="center"
        actions={
          <Button
            variant="ghost"
            size="icon"
            aria-label="デジタル会員証を表示"
            onClick={() => setMemberOpen(true)}
          >
            <IconCreditCard className="size-5" />
          </Button>
        }
      />

      <main className="flex w-full flex-1 flex-col gap-5 px-4 pt-4">
        {/* 会員証 / ポイント hero */}
        <LoyaltySummaryCard
          meta={
            <span>
              JRE POINT 会員証
              <br />
              {MEMBER.name} 様
            </span>
          }
          tier={<Badge variant="warning">{MEMBER.tier}</Badge>}
          balanceLabel="ポイント残高"
          balance={MEMBER.points.toLocaleString("ja-JP")}
          unit="P"
          secondary={[
            { label: "IC残高", value: yen(MEMBER.icBalance) },
            { label: "会員番号", value: MEMBER.memberNo.slice(-4).padStart(8, "•") },
          ]}
          progress={{
            value: MEMBER.tierProgress.value,
            max: MEMBER.tierProgress.max,
            label: MEMBER.tierProgress.remainLabel,
            caption: `${MEMBER.tierProgress.value.toLocaleString("ja-JP")} / ${MEMBER.tierProgress.max.toLocaleString("ja-JP")}P`,
          }}
          alert={`${MEMBER.expiringPoints.amount}P が ${MEMBER.expiringPoints.date} に失効予定`}
          action={
            <Button
              variant="secondary"
              className="w-full"
              onClick={() => setMemberOpen(true)}
            >
              <IconBarcode className="size-4" />
              会員証を表示
            </Button>
          }
        />

        {/* 特集 / おでかけプラン */}
        <Card className="overflow-hidden">
          <CardHeader className="gap-1.5 p-4 pb-2">
            <Badge variant="info" className="w-fit">
              {FEATURE.eyebrow}
            </Badge>
            <CardTitle as="h2" className="text-lg leading-snug">
              {FEATURE.title}
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <p className="text-sm text-muted-foreground">{FEATURE.description}</p>
            <List variant="ordered" marker="number" className="mt-3 text-foreground" spacing="tight">
              {FEATURE.steps.map((s) => (
                <ListItem key={s} className="text-sm">
                  {s}
                </ListItem>
              ))}
            </List>
          </CardContent>
        </Card>

        {/* 使えるクーポン */}
        <section aria-labelledby="coupons-heading" className="flex flex-col gap-2.5">
          <div className="flex items-baseline justify-between">
            <h2
              id="coupons-heading"
              className="flex items-center gap-1.5 text-base font-semibold text-foreground"
            >
              <IconTicket className="size-5 text-primary" />
              使えるクーポン
            </h2>
            <span className="text-xs text-muted-foreground">{COUPONS.length}件</span>
          </div>
          <div className="flex flex-col gap-2">
            {COUPONS.map((c) => (
              <ListCard
                key={c.id}
                onSelect={() => setOpenCoupon(c)}
                leading={
                  <span className="flex size-11 items-center justify-center rounded-lg bg-primary/10 text-primary">
                    <IconTicket className="size-6" aria-hidden="true" />
                  </span>
                }
                title={c.title}
                description={c.shop}
                tags={
                  <>
                    <Badge variant="success">{c.benefit}</Badge>
                    {c.limited && <Badge variant="warning">期間限定</Badge>}
                  </>
                }
                meta={`〜${c.expires}`}
                status={
                  <span className="text-xs font-medium text-primary">使う</span>
                }
              />
            ))}
          </div>
        </section>

        <Separator />

        {/* おすすめスポット + カテゴリ絞り込み */}
        <section aria-labelledby="spots-heading" className="flex flex-col gap-3">
          <div className="flex items-baseline justify-between">
            <h2
              id="spots-heading"
              className="flex items-center gap-1.5 text-base font-semibold text-foreground"
            >
              <IconMapPin className="size-5 text-primary" />
              おすすめスポット
            </h2>
          </div>

          <FilterChips
            items={chips}
            value={category}
            onValueChange={(v) => setCategory(v as Category)}
            aria-label="カテゴリで絞り込み"
          />

          {visibleSpots.length === 0 ? (
            <EmptyState
              icon={<IconMoodEmpty className="size-8" />}
              title="該当するスポットがありません"
              description="ほかのカテゴリを選んでみてください。"
            />
          ) : (
            <div className="flex flex-col gap-2">
              {visibleSpots.map((s) => (
                <ListCard
                  key={s.id}
                  onSelect={() => setOpenSpot(s)}
                  leading={
                    <span className="flex size-11 items-center justify-center rounded-lg bg-muted text-muted-foreground">
                      {CATEGORY_ICON[s.category]}
                    </span>
                  }
                  title={s.name}
                  description={s.reason}
                  tags={
                    <>
                      <Badge variant="outline">{CATEGORY_LABEL[s.category]}</Badge>
                      <Badge variant={s.gate === "inside" ? "info" : "secondary"}>
                        {gateLabel(s.gate)}
                      </Badge>
                      {s.couponId && (
                        <Badge variant="success">
                          <IconTicket className="size-3" aria-hidden="true" />
                          クーポン
                        </Badge>
                      )}
                    </>
                  }
                  meta={
                    <span className="inline-flex items-center gap-0.5">
                      <IconWalk className="size-3.5" aria-hidden="true" />
                      徒歩{s.walkMinutes}分
                    </span>
                  }
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {/* ===== スポット詳細 ===== */}
      <SpotDetailSheet
        spot={openSpot}
        onOpenChange={(o) => !o && setOpenSpot(null)}
        onUseCoupon={(c) => {
          setOpenSpot(null)
          setOpenCoupon(c)
        }}
      />

      {/* ===== クーポン提示券面 ===== */}
      <CouponRedeemSheet coupon={openCoupon} onOpenChange={(o) => !o && setOpenCoupon(null)} />

      {/* ===== デジタル会員証 ===== */}
      <MemberCardSheet open={memberOpen} onOpenChange={setMemberOpen} />
    </div>
  )
}

/* ------------------------------------------------------------------ */
/* スポット詳細 (bottom sheet)                                          */
/* ------------------------------------------------------------------ */
function SpotDetailSheet({
  spot,
  onOpenChange,
  onUseCoupon,
}: {
  spot: Spot | null
  onOpenChange: (open: boolean) => void
  onUseCoupon: (c: Coupon) => void
}) {
  const coupon = spot?.couponId ? COUPON_BY_ID[spot.couponId] : undefined
  return (
    <Sheet open={spot != null} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="mx-auto max-w-[420px] max-h-[88dvh] overflow-y-auto rounded-t-2xl"
      >
        {spot && (
          <>
            <SheetHeader className="text-left">
              <div className="mb-1 flex flex-wrap gap-1.5">
                <Badge variant="outline">{CATEGORY_LABEL[spot.category]}</Badge>
                <Badge variant={spot.gate === "inside" ? "info" : "secondary"}>
                  {gateLabel(spot.gate)}
                </Badge>
                {spot.badges?.map((b) => (
                  <Badge key={b} variant="secondary">
                    {b}
                  </Badge>
                ))}
              </div>
              <SheetTitle>{spot.name}</SheetTitle>
              <SheetDescription>{spot.reason}</SheetDescription>
            </SheetHeader>

            <dl className="mt-4 flex flex-col gap-3 text-sm">
              <Detail icon={<IconMapPin className="size-4" />} label="場所・行き方">
                {spot.place}・改札から徒歩{spot.walkMinutes}分
              </Detail>
              <Detail icon={<IconClock className="size-4" />} label="営業時間">
                {spot.hours}
              </Detail>
            </dl>

            {coupon && (
              <>
                <Separator className="my-4" />
                <p className="mb-2 text-sm font-semibold text-foreground">関連クーポン</p>
                <ListCard
                  onSelect={() => onUseCoupon(coupon)}
                  leading={
                    <span className="flex size-10 items-center justify-center rounded-lg bg-primary/10 text-primary">
                      <IconTicket className="size-5" aria-hidden="true" />
                    </span>
                  }
                  title={coupon.title}
                  description={coupon.shop}
                  tags={<Badge variant="success">{coupon.benefit}</Badge>}
                  status={<span className="text-xs font-medium text-primary">使う</span>}
                />
              </>
            )}
          </>
        )}
      </SheetContent>
    </Sheet>
  )
}

function Detail({
  icon,
  label,
  children,
}: {
  icon: React.ReactNode
  label: string
  children: React.ReactNode
}) {
  return (
    <div className="flex gap-2.5">
      <span className="mt-0.5 shrink-0 text-muted-foreground" aria-hidden="true">
        {icon}
      </span>
      <div className="min-w-0">
        <dt className="text-xs text-muted-foreground">{label}</dt>
        <dd className="text-foreground">{children}</dd>
      </div>
    </div>
  )
}

/* ------------------------------------------------------------------ */
/* クーポン提示券面 (bottom sheet)                                       */
/* ------------------------------------------------------------------ */
function CouponRedeemSheet({
  coupon,
  onOpenChange,
}: {
  coupon: Coupon | null
  onOpenChange: (open: boolean) => void
}) {
  return (
    <Sheet open={coupon != null} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="mx-auto max-w-[420px] max-h-[92dvh] overflow-y-auto rounded-t-2xl"
      >
        {coupon && (
          <>
            <SheetHeader className="text-left">
              <SheetTitle>{coupon.title}</SheetTitle>
              <SheetDescription>{coupon.shop}</SheetDescription>
            </SheetHeader>

            <StubFrame>
              <div className="flex flex-col items-center gap-1 px-5 pt-5 pb-3 text-center">
                <Badge variant="success" className="h-6 px-3 text-sm">
                  {coupon.benefit}
                </Badge>
                {coupon.limited && (
                  <span className="text-xs font-medium text-warning-strong">期間限定</span>
                )}
              </div>

              <div
                className="mx-5 mb-1 border-t border-dashed border-border"
                aria-hidden="true"
              />

              <div className="flex flex-col items-center gap-3 px-5 pb-5 pt-3">
                <p className="text-center text-xs text-muted-foreground">
                  レジでこの画面を提示してください
                </p>
                <Barcode value={coupon.barcodeValue} label={coupon.barcodeValue} className="w-full" />
                <div className="text-center font-mono text-sm text-muted-foreground">
                  コード: {coupon.code}
                </div>
              </div>
            </StubFrame>

            <dl className="mt-4 flex flex-col gap-2 text-sm">
              <div className="flex items-center justify-between">
                <dt className="text-muted-foreground">利用期限</dt>
                <dd className="font-medium tabular-nums text-foreground">{coupon.expires}</dd>
              </div>
            </dl>

            <p className="mt-3 rounded-md bg-muted px-3 py-2 text-xs leading-relaxed text-muted-foreground">
              {coupon.terms}
            </p>

            <Button className="mt-4 w-full" variant="primary" onClick={() => onOpenChange(false)}>
              閉じる
            </Button>
          </>
        )}
      </SheetContent>
    </Sheet>
  )
}

/* ------------------------------------------------------------------ */
/* デジタル会員証 (bottom sheet)                                         */
/* ------------------------------------------------------------------ */
function MemberCardSheet({
  open,
  onOpenChange,
}: {
  open: boolean
  onOpenChange: (open: boolean) => void
}) {
  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="mx-auto max-w-[420px] max-h-[92dvh] overflow-y-auto rounded-t-2xl"
      >
        <SheetHeader className="text-left">
          <SheetTitle>デジタル会員証</SheetTitle>
          <SheetDescription>レジでバーコードまたはQRを提示してください</SheetDescription>
        </SheetHeader>

        <div className="mt-3 rounded-xl bg-gradient-to-br from-gunjo-deep to-gunjo-deepest p-5 text-primary-foreground">
          <div className="flex items-start justify-between">
            <div className="text-sm text-primary-foreground/70">JRE POINT 会員証</div>
            <Badge variant="warning">{MEMBER.tier}</Badge>
          </div>
          <div className="mt-2 text-2xl font-bold">{MEMBER.name} 様</div>
          <div className="mt-1 font-mono text-sm tracking-widest text-primary-foreground/80">
            会員番号 {MEMBER.memberNo}
          </div>
          <div className="mt-3 text-sm text-primary-foreground/70">
            ポイント残高{" "}
            <span className="text-lg font-bold text-primary-foreground tabular-nums">
              {MEMBER.points.toLocaleString("ja-JP")}
            </span>{" "}
            P
          </div>
        </div>

        <div className="mt-4 flex flex-col items-center gap-4 rounded-xl border border-border bg-card p-5">
          <Barcode
            value={MEMBER.memberNo.replace(/\s/g, "")}
            label={MEMBER.memberNo}
            className="w-full"
          />
          <div className="h-px w-full bg-border" />
          <div className="w-40">
            <QrCode value={MEMBER.memberNo.replace(/\s/g, "")} ariaLabel="会員証QRコード" />
          </div>
          <p className="inline-flex items-center gap-1 text-xs text-muted-foreground">
            <IconShieldCheck className="size-3.5" aria-hidden="true" />
            画面の明るさを上げると読み取りやすくなります
          </p>
        </div>

        <Button className="mt-4 w-full" variant="outline" onClick={() => onOpenChange(false)}>
          <IconChevronRight className="size-4 rotate-90" />
          閉じる
        </Button>
      </SheetContent>
    </Sheet>
  )
}

"use client"

import * as React from "react"

/**
 * HAND-ROLLED GAP FILLER.
 *
 * @gunjo/ui has NO consumer-side "show this code at the register" primitive.
 * `ScanInput` / `ScanGate` are the *operator* side (they consume a scanned code via
 * `onScan` and return a validation result). There is no `BarcodeCard` / `QrCode` /
 * `TicketStub` / `CouponStub` for the traveller to *display* a barcode/QR on their phone.
 *
 * So everything below — the deterministic barcode bars, the faux-QR matrix, and the
 * coupon-stub notch — is plain Tailwind. This is the single biggest missing primitive
 * for a B2C station/coupon app.
 */

/** Deterministic, content-derived bar widths so the same value always renders the same. */
function hashToBars(value: string, count = 48): number[] {
  let h = 2166136261
  const bars: number[] = []
  for (let i = 0; i < count; i++) {
    h ^= value.charCodeAt(i % value.length) + i
    h = Math.imul(h, 16777619)
    // 1..4 px-ish weight buckets
    bars.push((Math.abs(h) % 4) + 1)
  }
  return bars
}

export function Barcode({
  value,
  label,
  className,
}: {
  value: string
  /** The human-readable number under the bars. */
  label?: string
  className?: string
}) {
  const bars = React.useMemo(() => hashToBars(value), [value])
  return (
    <figure className={className} role="img" aria-label={`バーコード ${label ?? value}`}>
      <div
        className="flex h-20 w-full items-stretch justify-center gap-px overflow-hidden rounded-md bg-white px-3 py-2"
        aria-hidden="true"
      >
        {bars.map((w, i) => (
          <span
            key={i}
            className="block h-full shrink-0 bg-black"
            style={{ width: `${w}px` }}
          />
        ))}
      </div>
      {label != null && (
        <figcaption className="mt-1.5 text-center font-mono text-sm tracking-[0.3em] text-foreground">
          {label}
        </figcaption>
      )}
    </figure>
  )
}

/** Deterministic faux-QR matrix derived from the value (purely visual). */
function hashToMatrix(value: string, size = 21): boolean[][] {
  let h = 0x811c9dc5
  const next = () => {
    h ^= h << 13
    h ^= h >>> 17
    h ^= h << 5
    return (h >>> 0) % 100
  }
  for (const ch of value) h = Math.imul(h ^ ch.charCodeAt(0), 16777619)
  const grid: boolean[][] = []
  for (let r = 0; r < size; r++) {
    const row: boolean[] = []
    for (let c = 0; c < size; c++) row.push(next() < 48)
    grid.push(row)
  }
  // Stamp the three finder squares so it reads as a QR.
  const stampFinder = (r0: number, c0: number) => {
    for (let r = 0; r < 7; r++) {
      for (let c = 0; c < 7; c++) {
        const edge = r === 0 || r === 6 || c === 0 || c === 6
        const core = r >= 2 && r <= 4 && c >= 2 && c <= 4
        grid[r0 + r][c0 + c] = edge || core
      }
    }
  }
  stampFinder(0, 0)
  stampFinder(0, size - 7)
  stampFinder(size - 7, 0)
  return grid
}

export function QrCode({
  value,
  className,
  ariaLabel = "QRコード",
}: {
  value: string
  className?: string
  ariaLabel?: string
}) {
  const grid = React.useMemo(() => hashToMatrix(value), [value])
  const size = grid.length
  return (
    <div
      className={className}
      role="img"
      aria-label={ariaLabel}
      style={{
        display: "grid",
        gridTemplateColumns: `repeat(${size}, 1fr)`,
        width: "100%",
        aspectRatio: "1 / 1",
        background: "#fff",
        padding: "8%",
        borderRadius: 8,
      }}
    >
      {grid.flatMap((row, r) =>
        row.map((on, c) => (
          <span
            key={`${r}-${c}`}
            aria-hidden="true"
            style={{ background: on ? "#000" : "transparent", aspectRatio: "1 / 1" }}
          />
        ))
      )}
    </div>
  )
}

/**
 * The coupon "stub" frame — a ticket card with a perforation notch on both sides, the
 * recurring 券面 look. Hand-rolled because no TicketStub/CouponStub primitive exists.
 */
export function StubFrame({ children }: { children: React.ReactNode }) {
  return (
    <div className="relative overflow-hidden rounded-xl border border-border bg-card">
      {/* perforation notches */}
      <span
        aria-hidden="true"
        className="absolute left-[-10px] top-1/2 size-5 -translate-y-1/2 rounded-full bg-background"
      />
      <span
        aria-hidden="true"
        className="absolute right-[-10px] top-1/2 size-5 -translate-y-1/2 rounded-full bg-background"
      />
      {children}
    </div>
  )
}
